head.script:
try {
  // Page start loading
  performance.mark("page_start");
  window.webSuccess = function () {
    return "success";
  };
} catch (error) {}

// Optimize: load js-base64 only when needed to avoid blocking first paint
(function () {
  // Check if URL contains encryption parameter
  const needsBase64 = window.location.search.includes("hoyto");

  if (needsBase64) {
    // If decryption is needed, load Base64 lib immediately
    var script = document.createElement("script");
    script.src = "https://cdn.jsdelivr.net/npm/js-base64@3.7.7/base64.min.js";
    // script.async = true;
    script.defer = true;
    document.head.appendChild(script);
  }
})();

// Ensure execution after DOMContentLoaded
document.addEventListener("DOMContentLoaded", function () {
  /**
   * Get all query parameters from current URL
   * @returns
   */
  function getQueryParams() {
    let identify = "hoyto"; // Key identifier
    const queryString = window.location.search.substring(1);
    const queryParams = {};
    const pairs = queryString.split("&");

    pairs.forEach((pair) => {
      const [key, value] = pair.split("=");
      if (key) {
        queryParams[key] = decodeURIComponent(value);
      }
    });

    // Compatible with new encapsulated encrypted content
    let encrypt = queryParams[identify];
    if (encrypt) {
      let moveLen = 10; // Shift length
      let queryEncrypt = caesarCipherDecrypt(encrypt, moveLen);
      const pairsEncrypt = queryEncrypt.split("&");
      pairsEncrypt.forEach((pair) => {
        const [key, value] = pair.split("=");
        if (key) {
          queryParams[key] = decodeURIComponent(value);
        }
      });
    }

    return queryParams;
  }

  function caesarCipherDecrypt(source, shift) {
    if (source.length < 1) {
      return source;
    }

    // Restrict shift between 1 and 25
    if (shift < 1) {
      shift = 1;
    } else if (shift > 25) {
      shift = 25;
    }

    let result = "";

    for (let i = 0; i < source.length; i++) {
      let char = source[i].charCodeAt(0);

      if (char >= "a".charCodeAt(0) && char <= "z".charCodeAt(0)) {
        char = ((char - shift - "a".charCodeAt(0) + 26) % 26) + "a".charCodeAt(0);
      } else if (char >= "A".charCodeAt(0) && char <= "Z".charCodeAt(0)) {
        char = ((char - shift - "A".charCodeAt(0) + 26) % 26) + "A".charCodeAt(0);
      }

      result += String.fromCharCode(char);
    }
    try {
      result = Base64.decode(result);
      return result;
    } catch {
      return result;
    }
  }

  const queryParams = getQueryParams();

  if (queryParams.apksource && queryParams.apksource == "wgapk") {
    localStorage.setItem("apksource", queryParams.apksource);
  }

  if (queryParams.channel && queryParams.channel_id) {
    localStorage.setItem("channel_name", queryParams.channel);
    localStorage.setItem("channel_id", queryParams.channel_id);
  }

  if (localStorage.getItem("channel_name") && localStorage.getItem("channel_id")) {
    initConfig(localStorage.getItem("channel_name"), localStorage.getItem("channel_id"));
  }

  function initConfig(channel, id) {
    // from roibest return
    if (queryParams.is_from_roibest && queryParams.is_from_roibest == 1) {
      return;
    }

    switch (channel) {
      case "OKSpinPixel":
        initOKSpinPixel(id);
        break;
      case "tiktok":
        initTiktokPixel(id);
        break;
      case "kwai":
        initKwaiPixel(id);
        break;
      case "MiniTrax":
        initMiniTrax(id);
        break;
    }
  }
  // Generic script injection: supports onload (with args), onerror callback, and custom attributes
  function appendScript(
    src,
    { async = false, defer = false, attrs = {}, onload = null, onloadArgs = [], onerror = null } = {}
  ) {
    const s = document.createElement("script");
    s.type = "text/javascript";
    if (async) s.async = true;
    if (defer) s.defer = true;
    for (const k in attrs) {
      try {
        s.setAttribute(k, attrs[k]);
      } catch (e) {}
    }
    s.src = src;
    s.onload = function () {
      try {
        if (typeof onload === "function") {
          // Pass argument array to onload callback
          onload.apply(this, onloadArgs || []);
        }
      } catch (e) {
        console.error("script onload handler error:", e);
      }
    };
    if (typeof onerror === "function") {
      s.onerror = onerror;
    }
    document.head.appendChild(s);
    return s;
  }

  function initMiniTrax(pixel) {
    if (!pixel) {
      return;
    }
    // Prefer CDN; fallback to local static file on load failure
    const remoteSrc = "https://res.minitrax.org/sdk/minitrax-tma.js";
    const localSrc = "/minitrax-tma.js"; // Ensure this file exists in public/minitrax-tma.js

    // onload callback receives pixel as first argument
    const initCallback = function (token) {
      try {
        if (window.minitrax && typeof window.minitrax.init === "function") {
          window.minitrax.init({ token: token });
          if (typeof window.minitrax.track === "function") {
            window.minitrax.track("opentma");
          }
        }
      } catch (e) {
        console.error("minitrax init error:", e);
      }
    };

    // Load remote script first, fallback to local on failure
    appendScript(remoteSrc, {
      onload: initCallback,
      defer: true,
      onloadArgs: [pixel],
      onerror: function () {
        console.warn("minitrax: remote load failed, fallback to local script:", localSrc);
        appendScript(localSrc, { onload: initCallback, defer: true, onloadArgs: [pixel] });
      },
    });
  }

  function initOKSpinPixel(pixel) {
    if (!pixel) {
      return;
    }
    let script = document.createElement("script");
    script.type = "text/javascript";
    // This resource does not block document loading
    script.src = "https://s.oksp.in/js/tag.js?aa=" + pixel;
    script.onload = () => {
      console.log("initOKSpinPixel-success");
    };
    document.head.appendChild(script);
  }

