html.script:
// Load third-party scripts after page load
window.addEventListener("load", function () {
  // Delay 1s to ensure first paint completes
  setTimeout(function () {
    // Load Microsoft Clarity when clarityKey is configured
    var clarityKey = "wbxpwyfl6m";
    if (clarityKey && clarityKey !== "undefined" && clarityKey.trim() !== "") {
      (function (c, l, a, r, i, t, y) {
        c[a] =
          c[a] ||
          function () {
            (c[a].q = c[a].q || []).push(arguments);
          };
        t = l.createElement(r);
        t.defer = true;
        t.src = "https://www.clarity.ms/tag/" + i;
        y = l.getElementsByTagName(r)[0];
        y.parentNode.insertBefore(t, y);
      })(window, document, "clarity", "script", clarityKey);
    }

    // Load a8r.games connector
    var connectorScript = document.createElement("script");
    connectorScript.src = "https://cdn.launcher.a8r.games/connector.js";
    connectorScript.defer = true;
    document.body.appendChild(connectorScript);

    // Load Facebook SDK
    var fbScript = document.createElement("script");
    fbScript.src = "https://connect.facebook.net/en_US/sdk.js";
    // fbScript.async = true;
    fbScript.defer = true;
    fbScript.crossOrigin = "anonymous";
    document.body.appendChild(fbScript);
  }, 1000);
});
